import{_ as s,C as t,o as h,c as p,j as e,a as n,E as i,a3 as c}from"./chunks/framework.CVjg771q.js";const q=JSON.parse('{"title":"列子·黄帝篇","description":"借黄帝问道与得道故事展开列子式修养想象，探讨无为而治、至人境界与心灵功夫。","frontmatter":{"title":"列子·黄帝篇","description":"借黄帝问道与得道故事展开列子式修养想象，探讨无为而治、至人境界与心灵功夫。","category":"guide","aliases":["黄帝篇","列子黄帝篇","liezi chapter 02"],"source":["《列子》","维基文库：列子·黄帝篇"]},"headers":[],"relativePath":"daoism/texts/lie-zi/chapter-02.md","filePath":"daoism/texts/lie-zi/chapter-02.md","lastUpdated":1778126077000}'),m={name:"daoism/texts/lie-zi/chapter-02.md"};function x(u,a,b,_,f,g){const r=t("DaoReadingPrelude"),l=t("DaoOriginalReadingGroup"),o=t("DaoLineGuide"),d=t("DaoKeywordCards");return h(),p("div",null,[a[0]||(a[0]=e("h1",{id:"列子·黄帝篇",tabindex:"-1"},[n("列子·黄帝篇 "),e("a",{class:"header-anchor",href:"#列子·黄帝篇","aria-label":'Permalink to "列子·黄帝篇"'},"​")],-1)),i(r,{title:"从黄帝梦游到列子御风，看修养的层层递进",summary:"黄帝篇是《列子》中篇幅最长、故事最丰富的一篇。它围绕黄帝、列子、商丘开、梁鸯、杨朱、老聃、壶丘子等多个人物，以一连串寓言展开关于「修养境界」的讨论。核心线索是：一个人从被物欲和忧虑所困，到「心凝形释」，再到「不知我之是非利害」——修养不是增加什么，而是一层层放下什么。",points:[{label:"先看",text:"顺着故事走：黄帝梦华胥氏→列子师老商氏→商丘开→梁鸯饲虎→津人操舟→孔子观吕梁→疴偻承蜩→杨朱→老聃与列子。"},{label:"再问",text:"列子「九年之后，不知我之是非利害」——这和庄子的「吾丧我」有什么相通之处？"},{label:"最后",text:"「至人潜行不窒，蹈火不热」——这种描述是字面意义上的还是象征意义上的？你怎么理解？"}],hint:"黄帝篇故事密集，每个故事都可以独立阅读。建议挑自己最有感觉的一个故事先读，比如梁鸯饲虎或疴偻承蜩。"}),a[1]||(a[1]=e("h2",{id:"【原典层】原文",tabindex:"-1"},[n("【原典层】原文 "),e("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),i(l,{paragraphs:["黃帝即位十有五年，喜天下戴己，養正命，娛耳目，供鼻口，焦然肌色皯黣，昏然五情爽惑。又十有五年，憂天下之不治，竭聰明，進智力，營百姓，焦然肌色皯黣，昏然五情爽惑。黃帝乃喟然讚曰：「朕之過淫矣。養一己其患如此，治萬物其患如此。於是放萬機，舍宮寢，去直侍，徹鐘懸。減廚膳，退而間居大庭之館，齋心服形，三月不親政事。晝寢而夢，遊於華胥氏之國。華胥氏之國在弇州之西，台州之北，不知斯齊國幾千萬里；蓋非舟車足力之所及，神游而已。其國无師長，自然而已。其民无嗜慾，自然而已。不知樂生，不知惡死，故无夭殤；不知親己，不知踈物，故无愛憎；不知背逆，不知向順，故无利害；都无所愛惜，都无所畏忌。入水不溺，入火不熱。","斫撻无傷痛，指擿无痟癢。乘空如履實，寢虛若處床。雲霧不硋其視，雷霆不亂其聽，美惡不滑其心，山谷不躓其步，神行而已。黃帝既寤，怡然自得，召天老、力牧、大山稽，告之曰：「朕閒居三月，齋心服形，思有以養身治物之道，弗獲其術。疲而睡，所夢若此。今知至道不可以情求矣。朕知之矣！朕得之矣！而不能以告若矣。又二十有八年，天下大治，幾若華胥氏之國，而帝登假。百姓號之，二百餘年不輟。列子師老商氏，友伯高子；進二子之道，乘風而歸。尹生聞之，從列子居，數月不省舍。因間請蘄其術者，十反而十不告。尹生懟而請辭，列子又不命。尹生退。數月，意不已，又往從之。列子曰：「汝何去來之頻？","尹生曰：「曩章戴有請於子，子不我告，固有憾於子。今復脫然，是以又來。列子曰：「曩吾以汝為達，今汝之鄙至此乎？將告汝所學於夫子者矣。自吾之事夫子友若人也，三年之後，心不敢念是非，口不敢言利害，始得夫子一眄而已。五年之後，心庚念是非，口庚言利害，夫子始一解顏而笑。七年之後，從心之所念，庚无是非；從口之所言，庚无利害，夫子始一引吾並席而坐。九年之後，橫心之所念，橫口之所言，亦不知我之是非利害歟，亦不知彼之是非利害歟；亦不知夫子之為我師，若人之為我友：內外進矣。而後眼如耳，耳如鼻，鼻如口，无不同也。心凝形釋，骨肉都融；不覺形之所倚，足之所履，隨風東西，猶木葉幹殼。竟不知風乘我邪？我乘風乎？","今女居先生之門，曾未浹時，而懟憾者再三。女之片體將氣所不受，汝之一節將地所不載。履虛乘風，其可幾乎？尹生甚怍，屏息良久，不敢復言。列子問關尹曰：「至人潛行不窒，蹈火不熱，行乎萬物之上而不慄。請問何以至於此？關尹曰：「是純氣之守也，非智巧果敢之列。魚語女。凡有貌像聲色者，皆物也。物與物何以相遠也？夫奚足以至乎先？是色而已。則物之造乎不形，而止乎无所化。夫得是而窮之者，焉得而正焉？彼將處乎不深之度，而藏乎无端之紀，游乎萬物之所終始。壹其性，養其氣，含其德，以通乎物之所造。夫若是者，其天守全，其神无郤，物奚自入焉？夫醉者之墜於車也，雖疾不死。骨節與人同，而犯害與人異，其神全也。","乘亦弗知也，墜亦弗知也。死生驚懼不入乎其胸，是故遌物而不慴。彼得全於酒，而猶若是，而況得全於天乎？聖人藏於天，故物莫之能傷也。"]}),i(o,{lines:[{label:"黄帝梦游",text:"黄帝从「养一己其患如此，治万物其患如此」的困境中，通过「斋心服形」梦见华胥氏之国——那是一个不需要治理的国度。"},{label:"华胥之国",text:"「其国无师长，自然而已；其民无嗜欲，自然而已」——这是列子对理想社会的描述。"},{label:"不可告",text:"黄帝醒来后说：「朕得之矣！而不能以告若矣」——最高体会不能用语言传达。"},{label:"列子学道",text:"列子跟老商氏学道九年的递进：三年不敢念是非→五年始得一笑→七年师父让同席坐→九年不知彼我之是非。"},{label:"心凝形释",text:"「竟不知风乘我邪？我乘风乎？」——修养的最高境界是物我界限的消失。"},{label:"至人之境",text:"「至人潜行不窒，蹈火不热」——关尹解释：这是因为「纯气之守」，而非技巧和胆量。"},{label:"醉者坠车",text:"醉汉从车上摔下来不受伤，不是因为他有技巧，而是因为他「不知」——精神完整，不受惊吓。"}]}),a[2]||(a[2]=e("h2",{id:"【原典层】字词释义",tabindex:"-1"},[n("【原典层】字词释义 "),e("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),i(d,{items:[{term:"弇州",pinyin:["yān","zhōu"],explanation:"列子想象中的遥远地名，在兖州之西，华胥氏之国所在。"},{term:"華胥",pinyin:["huá","xū"],explanation:"列子理想中的国度名称，国民自然无为，无爱憎利害。"},{term:"皯黣",pinyin:["gǎn","měi"],explanation:"面色焦枯灰暗的样子。黄帝劳累后「焦然肌色皯黣」。"},{term:"斫撻",pinyin:["zhuó","tà"],explanation:"砍打、击打。华胥氏之民虽被砍打也「无伤痛」。"},{term:"痟癢",pinyin:["xiāo","yǎng"],explanation:"酸疼发痒。「指擿无痟癢」——触碰身体也不觉得酸疼痒。"},{term:"硋",pinyin:["ài"],explanation:"同「碍」，遮挡。云雾不硋其视——云雾也遮挡不了他们的视线。"},{term:"躓",pinyin:["zhì"],explanation:"绊倒。山谷不躓其步——崎岖山路也不会绊倒他们的脚步。"},{term:"懟",pinyin:["duì"],explanation:"怨恨。尹生「怼而请辞」——因列子不教他而生气要离开。"},{term:"曩",pinyin:["nǎng"],explanation:"从前、过去。列子引用尹生之前来的情形。"},{term:"遌",pinyin:["è"],explanation:"遇到、碰到。圣人遇到外物也不会害怕。"}]}),a[3]||(a[3]=c("",15))])}const y=s(m,[["render",x]]);export{q as __pageData,y as default};
